/* === 复选框基础样式 === */
input[type='checkbox'] {
  background: #000000; /* 纯黑基底 */
  box-shadow: 
    0 0 0 1px #0D0650,        /* 发光描边 */
    0 0 0 3px #000000,        /* 黑实色分隔层 */
