    inset 0 3px 8px rgba(13,6,80,0.6); /* 深蓝釉面质感 */
}

/* === 悬停状态 === */
input[type='checkbox']:hover {
  box-shadow: 
    0 0 0 1px #1a0b8c,
    0 0 0 3px #000000,
    0 0 0 4px #0D0650,
    inset 0 2px 10px rgba(26,11,140,0.8), /* 增强釉面 */
    0 0 20px #ffffff; /* 外发光效果 */
}

/* === 选中状态 === */
input[type='checkbox']:checked {
  background: #070330; /* 深蓝底色 */
  box-shadow: 
    0 0 0 1px #0D0650,
    0 0 0 3px #ffffff,
    0 0 0 4px #1a0b8c,
    inset 0 4px 12px rgba(13,6,80,0.9), /* 强化釉面 */
    0 0 25px #0D0650; /* 强外发光 */
