  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 120%;
  height: 100%;
  background-image: url("data:image/svg+xml,%3csvg width='100' height='100' viewBox='0 0 100 100' xmlns='http://www.w3.org/2000/svg'%3e%3cg fill='white'%3e%3ccircle cx='50' cy='25' r='20'/%3e%3ccircle cx='50' cy='25' r='20' transform='rotate(72, 50, 50)'/%3e%3ccircle cx='50' cy='25' r='20' transform='rotate(144, 50, 50)'/%3e%3ccircle cx='50' cy='25' r='20' transform='rotate(216, 50, 50)'/%3e%3ccircle cx='50' cy='25' r='20' transform='rotate(288, 50, 50)'/%3e%3c/g%3e%3c/svg%3e");

  background-size: 0.9em auto;  /* 五瓣花大小 (微调以适应新形状) */  
  background-position: center;          
  background-repeat: no-repeat;                
  animation: checkAnim 0.2s ease-in; 
