/*——————标题栏渐变+三层描边系统——————*/
.header-style,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
  /* 主背景：纯黑实色 */
  background: #000000;

  /* 三层发光描边效果 - 枯骨逢春主题 */
  border: 2px solid #0D0650;           /* 第一层：深蓝实色描边 */
  outline: 2px solid rgba(255, 255, 255, 0.5); /* 第二层：白色发光描边（增强透明度） */
  box-shadow: 
    0 0 0 4px rgba(13, 6, 80, 0.8),   /* 第三层：深蓝色发光效果 */
    0 0 15px 5px rgba(255, 255, 255, 0.15); /* 白色外发光（减弱亮度） */

  /* 圆角设置 */
  border-radius: 0px;

  /* 背景图片设置 - 深空梦核风格 */
  background-image: url('https://i.postimg.cc/1330z6T5/Image-1879451768533254.png');
  background-repeat: no-repeat;
  background-position: center;
  background-size: cover;

  /* 文字区域半透明遮罩 - 增强可读性 */
  position: relative;

  /* 添加平滑过渡效果 */
  transition: all 0.4s ease;
}

.header-style::before,
#extensions_settings .inline-drawer-toggle.inline-drawer-header::before,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header::before,
#user-settings-block h4::before,
.standoutHeader::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.8); /* 纯黑半透明遮罩（增强对比度） */
  border-radius: 0px; /* 直角匹配主元素 */
  z-index: 0;
  transition: all 0.4s ease;
}

/* 内部内容容器 - 确保内容在遮罩上方 */
.header-style > *,
#extensions_settings .inline-drawer-toggle.inline-drawer-header > *,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header > *,
#user-settings-block h4 > *,
.standoutHeader > * {
  position: relative;
  z-index: 1;

  /* 添加白色发光文字效果（增强可读性） */
  text-shadow: 0 0 10px rgba(255, 255, 255, 0.7);
}

/* 悬停效果 - 增强梦核感 */
.header-style:hover,
#extensions_settings .inline-drawer-toggle.inline-drawer-header:hover,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header:hover,
#user-settings-block h4:hover,
.standoutHeader:hover {
  /* 增强发光效果 */
  box-shadow: 
    0 0 0 4px rgba(13, 6, 80, 1),
    0 0 25px 10px rgba(255, 255, 255, 0.25); /* 减弱白光避免过曝 */

  /* 悬停时遮罩透明度降低 */
  &::before {
    background: rgba(0, 0, 0, 0.6); /* 保持纯黑遮罩 */
  }

  /* 添加轻微放大效果增强梦幻感 */
  transform: scale(1.01);
}

/* 夜间模式优化 */
@media (prefers-color-scheme: dark) {
  .header-style,
  #extensions_settings .inline-drawer-toggle.inline-drawer-header,
  #extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
  #user-settings-block h4,
  .standoutHeader {
    /* 夜间模式下加强发光效果 */
    box-shadow: 
      0 0 0 4px rgba(13, 6, 80, 0.9),
      0 0 20px 8px rgba(255, 255, 255, 0.2); /* 减弱白光 */

    /* 增强第二层白色描边 */
    outline: 3px solid rgba(255, 255, 255, 0.6);
  }

  .header-style:hover,
  #extensions_settings .inline-drawer-toggle.inline-drawer-header:hover,
  #extensions_settings2 .inline-drawer-toggle.inline-drawer-header:hover,
  #user-settings-block h4:hover,
  .standoutHeader:hover {
    box-shadow: 
      0 0 0 4px rgba(13, 6, 80, 1),
      0 0 30px 12px rgba(255, 255, 255, 0.3); /* 保持白光柔和 */
  }
}

