/* ===== 输入框美化 ===== */
input:not([type="file" i], [type="image" i], [type="checkbox" i], [type="radio" i]) {
  /* 深渊基底 */
  background: #000000; 
  border: 1px solid #0D0650; 
  border-radius: 0px;
  padding: 0.5rem 0.8rem;
  transition: all 0.25s ease;
  color: #E0F0FF; /* 冰蓝文字 */
  font-size: 0.6rem;
  height: 1.4rem;

  /* 三重发光结构 - 深蓝/白/深蓝 */
  box-shadow: 
    inset 0 0 0 1px rgba(13, 6, 80, 0.6), /* 内层深蓝描边 */
    0 0 0 2px #FFFFFF,                     /* 白色中层描边 */
    0 0 15px rgba(13, 6, 80, 0.5);        /* 外层深蓝辉光 */
}

/* 聚焦状态 - 白骨觉醒 */
