  outline: none;
  transform: translateY(-1px);
  border-color: #0D0650;
  box-shadow: 
    inset 0 0 0 1px rgba(13, 6, 80, 0.8),
    0 0 0 3px #FFFFFF,                     /* 强化白光框 */
    0 0 25px rgba(255, 255, 255, 0.5),     /* 白光晕 */
    inset 0 0 10px rgba(13, 6, 80, 0.9);   /* 深蓝内透 */
}

/* 悬停状态 - 深蓝悸动 */
input:hover {
  background: #0A0A1A; /* 深蓝涟漪 */
  border-color: #1A1F8C;
  box-shadow: 
    inset 0 0 0 1px rgba(13, 6, 80, 0.7),
    0 0 0 2px #FFFFFF,                     /* 白色描边 */
    0 0 20px rgba(13, 6, 80, 0.8);         /* 深蓝辉光 */
}

/* 禁用状态 - 枯骨沉寂 */
input:disabled {
  background: #050510; 
  color: #5D5D9F;      /* 褪色深蓝 */
  cursor: not-allowed;
  border-color: #0A0A20; /* 深蓝黑 */
  box-shadow: 
    inset 0 0 0 1px rgba(13, 6, 80, 0.3),
    0 0 0 2px #555577;   /* 灰蓝描边 */
}
