/* ========== 顶部渐变遮罩 ========== */
#chat {
  /* 保留原有样式 */
  max-height: calc(100vh - calc(var(--topBarBlockSize) + var(--bottomFormBlockSize)));
  overflow-x: hidden;
  padding-bottom: 0;
  overflow-y: scroll;
  display: flex;
  bottom: 10px;
  backdrop-filter: blur(var(--SmartThemeBlurStrength));
  background-color: var(--SmartThemeChatTintColor);
  -webkit-backdrop-filter: blur(var(--SmartThemeBlurStrength));
  text-shadow: 0px 0px calc(var(--shadowWidth) * 1px) var(--SmartThemeShadowColor);
  flex-direction: column;
  z-index: 30;
  flex-grow: 1;

 /* 顶部渐变遮罩 */
  --top-fade-height: 40px; /* 顶部渐变区域高度 */
  --top-fade-start: 0px; /* 顶部开始渐变的位置（0=从顶部开始） */

  /* 底部渐变遮罩 */
  --bottom-fade-start: 100px; /* 底部渐变开始位置 */
  --bottom-fade-height: 99px; /* 底部渐变区域高度 */
  --bottom-fade-end: 0px; /* 完全消失位置 */

  /* 组合遮罩效果 */
  mask-image: 

    /* 顶部遮罩：上虚下实 */
    linear-gradient(
      to bottom, 
      rgba(0,0,0,0) var(--top-fade-start), 
      rgba(0,0,0,1) calc(var(--top-fade-start) + var(--top-fade-height))
    ),

    /* 底部遮罩：上实下虚 */
    linear-gradient(
      to bottom, 
      rgba(0,0,0,1) 0%, 
      rgba(0,0,0,1) calc(100% - var(--bottom-fade-start)), 
      rgba(0,0,0,0) calc(100% - var(--bottom-fade-end))
    );
  -webkit-mask-image: 
    linear-gradient(
      to bottom, 
      rgba(0,0,0,0) var(--top-fade-start), 
      rgba(0,0,0,1) calc(var(--top-fade-start) + var(--top-fade-height))
    ),
    linear-gradient(
      to bottom, 
      rgba(0,0,0,1) 0%, 
      rgba(0,0,0,1) calc(100% - var(--bottom-fade-start)), 
      rgba(0,0,0,0) calc(100% - var(--bottom-fade-end))
    );
  mask-size: 100% 100%;
  -webkit-mask-size: 100% 100%;
  mask-composite: intersect; /* 组合两个遮罩 */
  -webkit-mask-composite: source-in; /* Safari兼容 */
}
